/*
 * flair_clut8_rgb_to_index -- contract for the nearest-index function.
 *
 * Maps an 8-bit RGB triple to the nearest CLUT index using squared
 * Euclidean distance in (R,G,B) space. On a tie, the LOWER index wins
 * (stable / deterministic).
 *
 * This contract is PURE FUNCTION: same inputs always produce the same
 * output regardless of call order (Law 2 determinism; Rule 11
 * reproducibility). No global state, no randomness.
 *
 * Ref: system7-decomp/specs/resources/clut-pltt-format.md Sec 6
 *   (FLAIR consumer mapping: imaging.h Color2Index).
 *   era: system7.0-7.1.
 *
 * Known mappings (verified vs flair_clut8[] above):
 *   (255,255,255) -> 0    (white; cube vertex; dist=0)
 *   (0,0,0)       -> 255  (black; exact; dist=0)
 *   (51,153,0)    -> 161  (IM "medium green"; cube vertex; dist=0)
 *   (102,102,102) -> 129  (cube gray #666666; dist=0)
 *
 * Implementation: harness/proptest/test_clut.c provides the reference
 * O(256) linear scan. Production callers may substitute a faster structure
 * (e.g. a kd-tree) provided the determinism contract holds.
 */
static inline unsigned char flair_clut8_rgb_to_index(
        unsigned char r, unsigned char g, unsigned char b)
{
    unsigned char best = 0;
    unsigned long best_d = 0xFFFFFFFFUL;
    unsigned int i;
    for (i = 0; i < 256; i++) {
        long dr = (long)r - (long)flair_clut8[i][0];
        long dg = (long)g - (long)flair_clut8[i][1];
        long db = (long)b - (long)flair_clut8[i][2];
        unsigned long d = (unsigned long)(dr*dr + dg*dg + db*db);
        if (d < best_d) {
            best_d = d;
            best = (unsigned char)i;
        }
    }
    return best;
}

